   204	        /// <summary>
   205	        /// Toggles the expanded or collapsed state of the specified group by column name and key.
   206	        /// </summary>
   207	        /// <param name="columnName">The name of the grouped column.</param>
   208	        /// <param name="key">The group key identifying the specific group to expand or collapse.</param>
   209	        /// <param name="expanded">Whether the group should be expanded (true) or collapsed (false).</param>
   210	        public void ToggleGroupExpand(string? columnName, object? key, bool expanded)
   211	        {
   212	            var groupKey = new GroupKey(columnName, key);
   213	
   214	            // update the expansion state for _groupExpansionsDict
   215	            // if it has a key we see if it differs from the definition Expanded State and update accordingly
   216	            // if it doesn't we add it if the new state doesn't match the definition
   217	            var col = RenderedColumns.FirstOrDefault(x => x.PropertyName == columnName);
   218	            if (expanded == col?._groupExpandedState.Value)
   219	                _groupExpansionsDict.Remove(groupKey);
   220	            else
   221	                _groupExpansionsDict[groupKey] = expanded;
   222	
   223	            _groupInitialExpanded = false;
   224	            StateHasChanged();
   225	        }
