   272	        public async Task ExpandAllHierarchy()
   273	        {
   274	            Debug.Assert(_buttonDisabledFunc is not null);
   275	            var expandedItems = FilteredItems.Where(x => !_buttonDisabledFunc(x) && _openHierarchies.Add(x));
   276	            foreach (var item in expandedItems)
   277	            {
   278	                await HierarchyVisibilityToggled.InvokeAsync(new(item, true));
   279	            }
   280	            await InvokeAsync(StateHasChanged);
   281	        }
   282	
   283	        /// <summary>
   284	        /// Collapses all Hierarchy columns
   285	        /// </summary>
   286	        public async Task CollapseAllHierarchy()
   287	        {
   288	            Debug.Assert(_buttonDisabledFunc is not null);
   289	            foreach (var openedHierarchy in _openHierarchies.Where(x => !_buttonDisabledFunc(x)).ToList())
   290	            {
   291	                await HierarchyVisibilityToggled.InvokeAsync(new(openedHierarchy, false));
   292	                _openHierarchies.Remove(openedHierarchy);
   293	            }
   294	            await InvokeAsync(StateHasChanged);
   295	        }
   296	
   297	        /// <summary>
   298	        /// Collapses or expands the hierarchy of the specified item.
   299	        /// </summary>
   300	        /// <param name="item">The item whose hierarchy visibility is to be toggled.</param>
   301	        public async Task ToggleHierarchyVisibilityAsync(T item)
   302	        {
   303	            // if ExpandSingleRow is true, clear all open hierarchies, which will immediately add the item that was clicked.
   304	            if (_expandSingleRowState.Value)
   305	            {
   306	                foreach (var openedHierarchy in _openHierarchies.Where(x => x != null && !x.Equals(item)))
   307	                {
   308	                    await HierarchyVisibilityToggled.InvokeAsync(new(openedHierarchy, false));
   309	                }
   310	                _openHierarchies.Clear();
   311	                _openHierarchies.Add(item);
   312	                await InvokeAsync(StateHasChanged);
   313	                return;
   314	            }
   315	
   316	            // if item doesn't exist remove will return false and add the item
   317	            if (!_openHierarchies.Remove(item))
   318	            {
   319	                _openHierarchies.Add(item);
   320	                await HierarchyVisibilityToggled.InvokeAsync(new(item, true));
   321	            }
   322	            else
   323	            {
   324	                await HierarchyVisibilityToggled.InvokeAsync(new(item, false));
   325	            }
   326	
   327	            await InvokeAsync(StateHasChanged);
   328	        }
